static const int MOB_SKILLS_N = 3648;

inline const MobSkillRow* mobskill_info(unsigned id) {
    int lo = 0, hi = MOB_SKILLS_N - 1;
    while (lo <= hi) { int mid = (lo + hi) >> 1;
        if (MOB_SKILLS[mid].id == id) return &MOB_SKILLS[mid];
        if (MOB_SKILLS[mid].id < id) lo = mid + 1; else hi = mid - 1; }
    return 0;
}

